sys_script.script:
// Auto-approve renewals with minimal premium changes
if (current.getValue('renewal_status') == 'pending' && 
    current.getValue('renewal_type') == 'automatic') {

    var oldPremium = parseFloat(current.getValue('previous_premium') || 0);
    var newPremium = parseFloat(current.getValue('new_premium') || 0);

    if (oldPremium > 0) {
        var changePercent = Math.abs((newPremium - oldPremium) / oldPremium) * 100;

        // Auto-approve if premium change is less than 10%
        if (changePercent < 10) {
            current.setValue('renewal_status', 'approved');
            current.setValue('agent_notes', 
                           (current.getValue('agent_notes') || '') + 
                           '\n[Auto-approved] Low-risk renewal with ' + 
                           Math.round(changePercent * 100) / 100 + '% premium change.');

            gs.addInfoMessage('Renewal auto-approved due to minimal premium change.');
        }
    }
}
